mapper.select:
SELECT th.history_id AS historyId, p.project_title AS projectTitle, u.user_name AS userName, t.task_title AS taskTitle, tt.type_name AS typeName, cc.default_describe AS defaultDescribe, th.action_type actionType, th.action_at + INTERVAL '9' HOUR AS actionAt FROM task_history th INNER JOIN task t ON th.task_id = t.task_id INNER JOIN project p ON t.project_id = p.project_id INNER JOIN users u ON th.changed_by = u.user_code INNER JOIN task_types tt ON t.type_id = tt.type_id LEFT OUTER JOIN work_time w ON t.task_id = w.task_id LEFT OUTER JOIN common_code cc ON t.task_status = cc.common_code AND cc.common_id = '0E'
AND p.project_id = #{projectId}
AND u.user_code = #{userCode}
AND th.action_at >= TO_DATE(#{startDate}, 'YYYY.MM.DD') - INTERVAL '9' HOUR
AND th.action_at < TO_DATE(#{endDate}, 'YYYY.MM.DD') + INTERVAL '1' DAY - INTERVAL '9' HOUR
AND tt.type_name IN
#{type}
ORDER BY th.action_at DESC
